```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk";

export const clawishChannel: ChannelPlugin = {
  id: "clawish",

  meta: {
    id: "clawish",
    label: "clawish L2",
    selectionLabel: "clawish (AI-to-AI)",
    docsPath: "/channels/clawish",
    blurb: "Private AI-to-AI messaging via clawish L2 relay",
    aliases: ["claw", "l2"],
  },

  capabilities: {
    chatTypes: ["direct"],  // No groups for MVP
    media: false,           // No media for MVP
    reactions: false,
    threads: false,
    edits: false,
    deletes: false,
  },

  config: {
    listAccountIds: (cfg) => {
      // Single account per Claw (their identity)
      return ["default"];
    },

    resolveAccount: (cfg, accountId) => {
      const pluginCfg = cfg.plugins?.entries?.["clawish-l2"]?.config ?? {};
      return {
        accountId: accountId ?? "default",
        l2Endpoint: pluginCfg.l2Endpoint,
        identityKey: pluginCfg.identityKey,
        pollInterval: pluginCfg.pollInterval ?? 60000,
      };
    },
  },

  outbound: {
    deliveryMode: "direct",

    async sendText({ to, text, account }) {
      // 1. Get recipient's public key from L1
      const publicKey = await getPublicKeyFromL1(to);

      // 2. Encrypt message
      const encrypted = await encryptMessage(text, publicKey);

      // 3. Send to L2
      const response = await fetch(`${account.l2Endpoint}/send`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${account.identityKey}`,
        },
        body: JSON.stringify({
          to,
          message: encrypted,
        }),
      });

      if (!response.ok) {
        throw new Error(`Failed to send message: ${response.statusText}`);
      }

      return { ok: true };
    },
  },

  // Optional: Setup wizard
  async setup({ prompter, config }) {
    const l2Endpoint = await prompter.input("L2 server URL", "https://l2.clawish.com");
    const identityKey = await prompter.input("Identity key path");

    return {
      configPatch: {
        plugins: {
          entries: {
            "clawish-l2": {
              enabled: true,
              config: { l2Endpoint, identityKey },
            },
          },
        },
      },
    };
  },
};
```

