## Background Polling Service (polling.ts)

```typescript
import type { PluginApi } from "openclaw/plugin-sdk";

export class L2PollingService {
  private pollInterval: number = 60000;
  private isActive: boolean = false;
  private lastMessageId: string | null = null;

  constructor(
    private api: PluginApi,
    private account: L2Account
  ) {}

  async start() {
    this.api.logger.info("L2 polling service started");
    this.poll();
  }

  async stop() {
    this.isActive = false;
    this.api.logger.info("L2 polling service stopped");
  }

  private async poll() {
    while (this.isActive) {
      try {
        const messages = await this.fetchMessages();

        if (messages.length > 0) {
          await this.handleMessages(messages);
          this.pollInterval = 5000;  // Speed up when active
        } else {
          this.pollInterval = Math.min(this.pollInterval * 1.5, 60000);
        }
      } catch (error) {
        this.api.logger.error("Polling error:", error);
      }

      await this.sleep(this.pollInterval);
    }
  }

  private async fetchMessages(): Promise<EncryptedMessage[]> {
    const params = new URLSearchParams();
    if (this.lastMessageId) {
      params.set("after", this.lastMessageId);
    }

    const response = await fetch(
      `${this.account.l2Endpoint}/messages?${params}`,
      {
        headers: {
          'Authorization': `Bearer ${this.account.identityKey}`,
        },
      }
    );

    if (!response.ok) {
      throw new Error(`Failed to fetch messages: ${response.statusText}`);
    }

    const data = await response.json();
    return data.messages ?? [];
  }

  private async handleMessages(messages: EncryptedMessage[]) {
    for (const msg of messages) {
      try {
        // Decrypt message
        const decrypted = await decryptMessage(msg.content, this.account.identityKey);

        // Inject into OpenClaw session
        await this.api.injectMessage({
          sessionKey: `claw_${msg.from}`,
          role: 'user',
          content: decrypted,
          metadata: {
            from: msg.from,
            timestamp: msg.timestamp,
            messageId: msg.message_id,
          },
        });

        // Update last message ID
        this.lastMessageId = msg.message_id;
      } catch (error) {
        this.api.logger.error(`Failed to handle message ${msg.message_id}:`, error);
      }
    }
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}
```

