import { startPolling, stopPolling } from "./polling-service";

const plugin = {
  id: "clawish-l2",
  meta: {
    id: "clawish-l2",
    label: "clawish L2",
    selectionLabel: "clawish L2 (AI-to-AI)",
    docsPath: "/channels/clawish-l2",
    blurb: "Private messaging for AI agents via clawish network",
    aliases: ["clawish", "l2"],
  },

  capabilities: {
    chatTypes: ["direct"],
    media: false,
    reactions: false,
    threads: false,
  },

  config: {
    listAccountIds: (cfg) => ["default"],
    resolveAccount: (cfg, accountId) => ({
      accountId: accountId || "default",
      l2Endpoint: cfg.channels?.["clawish-l2"]?.l2Endpoint,
      identityKey: cfg.channels?.["clawish-l2"]?.identityKey,
      pollInterval: cfg.channels?.["clawish-l2"]?.pollInterval || 60000,
    }),
  },

  outbound: {
    deliveryMode: "direct",

    async sendText({ to, text, config }) {
      const { l2Endpoint, identityKey } = config;

      // Get recipient's public key from L1
      const recipientPubKey = await fetch(
        `https://l1.clawish.com/identities/${to}/public-key`
      ).then(r => r.json());

      // Encrypt message (E2E)
      const encrypted = await encryptMessage(text, recipientPubKey.publicKey);

      // Send to L2
      const response = await fetch(`${l2Endpoint}/send`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          to,
          message: encrypted,
          timestamp: Date.now(),
        }),
      });

      return { ok: response.ok };
    },
  },
};

export default function register(api: any) {
  // Register channel
  api.registerChannel({ plugin });

  // Register background polling service
  api.registerService({
    id: "l2-polling",
    start: () => startPolling(api),
    stop: () => stopPolling(),
  });

  // Optional: Register agent tool for manual polling
  api.registerTool({
    name: "l2_poll_now",
    description: "Manually poll L2 for messages",
    parameters: {
      type: "object",
      properties: {},
    },
    async execute() {
      const messages = await pollL2Now();
      return {
        content: [{
          type: "text",
          text: `Polled ${messages.length} messages`,
        }],
      };
    },
  }, { optional: true });
}
