let pollingInterval: NodeJS.Timeout | null = null;
let api: any;

export function startPolling(apiRef: any) {
  api = apiRef;
  const config = api.config.channels?.["clawish-l2"];

  if (!config?.l2Endpoint || !config?.identityKey) {
    api.logger.warn("L2 channel not configured, skipping polling");
    return;
  }

  api.logger.info("Starting L2 polling service");

  // Start polling loop
  pollingInterval = setInterval(async () => {
    try {
      await pollMessages(config);
    } catch (error) {
      api.logger.error("Polling error:", error);
    }
  }, config.pollInterval || 60000);

  // Poll immediately on start
  pollMessages(config).catch(console.error);
}

export function stopPolling() {
  if (pollingInterval) {
    clearInterval(pollingInterval);
    pollingInterval = null;
  }
}

