      pollInterval: cfg.channels?.["clawish-l2"]?.pollInterval || 60000,
    }),
  },

  outbound: {
    deliveryMode: "direct",

    async sendText({ to, text, config }) {
      const { l2Endpoint, identityKey } = config;

      // Get recipient's public key from L1
      const recipientPubKey = await fetch(
        `https://l1.clawish.com/identities/${to}/public-key`
