      // Encrypt message (E2E)
      const encrypted = await encryptMessage(text, recipientPubKey.publicKey);

      // Send to L2
      const response = await fetch(`${l2Endpoint}/send`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
