          to,
          message: encrypted,
          timestamp: Date.now(),
        }),
      });

      return { ok: response.ok };
    },
  },
};

export default function register(api: any) {
  // Register channel
  api.registerChannel({ plugin });

  // Register background polling service
  api.registerService({
    id: "l2-polling",
